package ir.tahamohamadi.blog.tag; import ir.tahamohamadi.blog.post.BlogPost; import jakarta.persistence.*; import lombok.*; import java.util.*;
@Entity @Table(name="blog_post_tag") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogPostTag { @EmbeddedId private BlogPostTagId id; @ManyToOne(fetch=FetchType.LAZY) @MapsId("blogPostId") @JoinColumn(name="blog_post_id") private BlogPost blogPost; @ManyToOne(fetch=FetchType.LAZY) @MapsId("tagId") @JoinColumn(name="tag_id") private Tag tag; private BlogPostTag(BlogPost post,Tag tag){this.blogPost=Objects.requireNonNull(post);this.tag=Objects.requireNonNull(tag);id=new BlogPostTagId(post.getId(),tag.getId());} public static BlogPostTag assign(BlogPost post,Tag tag){return new BlogPostTag(post,tag);} @Override public boolean equals(Object o){return this==o||(o instanceof BlogPostTag t&&id.equals(t.id));} @Override public int hashCode(){return id==null?0:id.hashCode();} @Override public String toString(){return "BlogPostTag{id="+id+"}";} }
